final_sparql:
PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdf:     <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?constituent
       (?frac * ?itemMass AS ?kg)
       (?relUnc * ?frac * ?itemMass AS ?kgUncertainty)
WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030000_Y2030> ;
        rdf:type        <https://www.purl.org/futuram#elvEmbeddedElectronics> ;
        fq:itemMass     ?itemMass ;
        fq:contains     [ fq:constituent ?constituent ;
                          fq:amount ?frac ;
                          fq:relativeUncertainty ?relUnc ] .
  ?constituent rdfs:subClassOf* <https://www.purl.org/futuram#Element> .
}
ORDER BY DESC(?kg)

arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label   ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)), "embedded electronics") )
}
ORDER BY ?label

